// isFieldLockedIn reports whether a given field name appears in the artist's
// LockedFields slice. Comparison is case-insensitive to match backend
// canonicalization so a chip stored as "Biography" still matches a UI field
// named "biography".
func isFieldLockedIn(a *artist.Artist, field string) bool {
	if a == nil {
		return false
	}
	lf := strings.ToLower(field)
	for _, f := range a.LockedFields {
		if strings.ToLower(f) == lf {
			return true
		}
	}
	return false
}

